#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Trim leading and trailing spaces in place
static void trim(char *s) {
    char *end;
    while (*s && (*s == ' ' || *s == '\t')) s++;
    end = s + strlen(s) - 1;
    while (end >= s && (*end == ' ' || *end == '\t')) *end-- = '\0';
    memmove(s - (s - (char *)s), s, strlen(s) + 1); // shift to original buffer start
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char line[128];
    for (int i = 0; i < T; ++i) {
        if (!fgets(line, sizeof(line), stdin)) line[0] = '\0';
        // remove trailing newline
        line[strcspn(line, "\n")] = '\0';
        // trim spaces
        char *start = line;
        while (*start && (*start == ' ' || *start == '\t')) start++;
        char *end = start + strlen(start) - 1;
        while (end >= start && (*end == ' ' || *end == '\t')) *end-- = '\0';
        long long age = strtoll(start, NULL, 10);
        if (age < 0) {
            printf("INVALID AGE INPUT\n");
        } else if (age <= 12) {
            printf("CHILD\n");
        } else if (age <= 19) {
            printf("TEENAGER\n");
        } else if (age <= 64) {
            printf("ADULT\n");
        } else {
            printf("SENIOR\n");
        }
    }
    return 0;
}

