        for (int i = 0; i < T; i++) {
            String raw = br.readLine();
            if (raw == null) raw = "";
            String trimmed = raw.trim();
            long age = trimmed.isEmpty() ? 0 : Long.parseLong(trimmed);
            String out;
            if (age < 0) out = "INVALID AGE INPUT";
            else if (age <= 12) out = "CHILD";
            else if (age <= 19) out = "TEENAGER";
            else if (age <= 64) out = "ADULT";
            else out = "SENIOR";
            sb.append(out);
            if (i + 1 < T) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def classify(age: int) -> str:
    if age < 0:
        return "INVALID AGE INPUT"
    if age <= 12:
        return "CHILD"
    if age <= 19:
        return "TEENAGER"
    if age <= 64:
        return "ADULT"
    return "SENIOR"


def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T + 1):
        age_str = data[i].strip() if i < len(data) else ""
        age = int(age_str) if age_str else 0
        out.append(classify(age).upper())
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

